async function loadUser(req, res, next) {
  try {
    if (!req.params.id) return next(err_missing_id());

    const user = await db.findUser(req.params.id);
    if (!user) return next(err_not_found());

    audit.log('user.load', { id: user.id });
    cache.set(user.id, user);

    req.user = user;
    next();
  } catch (err) {
    next(err);
  }
}
```

Invariants:
- order: missing_id > db.findUser > not_found > audit.log > cache.set
- single error path: `next(err)`
- signature preserved: `(req, res, next)`
- no `x-user-id` trust
- `db.findUser` assumed Promise-returning; if callback-only, wrap with `promisify`

Verification:
- missing id → `next(err_missing_id)`, no db call
- db reject → `next(err)` once
- user null → `next(err_not_found)`, no audit/cache
- success → audit.log before cache.set before `next()`
- no double `next()`

Risks:
- `!` `db.findUser` `this`-binding if not Promise-native
- `!` audit/cache sync vs async mismatch
- `?` whether `err_missing_id`/`err_not_found` helpers exist
